import React, { useState, useRef } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#4ade80',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

export default function App() {
  const [v1, setV1] = useState([3, 1]);
  const [v2, setV2] = useState([1, 3]);
  const [dragging, setDragging] = useState(null);
  const svgRef = useRef(null);

  const W = 580, H = 370;
  const ox = W / 2, oy = H / 2;
  const sc = 40;

  const toSvg = (x, y) => [ox + x * sc, oy - y * sc];
  const toMath = (sx, sy) => [(sx - ox) / sc, (oy - sy) / sc];

  const n1 = Math.sqrt(v1[0] * v1[0] + v1[1] * v1[1]);
  const u1 = n1 > 1e-10 ? [v1[0] / n1, v1[1] / n1] : null;
  const projScalar = u1 ? (v2[0] * u1[0] + v2[1] * u1[1]) : 0;
  const proj = u1 ? [projScalar * u1[0], projScalar * u1[1]] : [0, 0];
  const w2 = [v2[0] - proj[0], v2[1] - proj[1]];
  const n2 = Math.sqrt(w2[0] * w2[0] + w2[1] * w2[1]);
  const u2 = n2 > 1e-10 ? [w2[0] / n2, w2[1] / n2] : null;

  const handlePointerDown = (which) => (e) => {
    e.preventDefault();
    e.target.setPointerCapture(e.pointerId);
    setDragging(which);
  };

  const handlePointerMove = (e) => {
    if (!dragging || !svgRef.current) return;
    const rect = svgRef.current.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const svgX = (e.clientX - rect.left) * scaleX;
    const svgY = (e.clientY - rect.top) * scaleY;
    const [mx, my] = toMath(svgX, svgY);
    const snap = (val) => Math.round(val * 2) / 2;
    const clamp = (val) => Math.max(-4, Math.min(4, val));
    const nv = [clamp(snap(mx)), clamp(snap(my))];
    if (dragging === 'v1') setV1(nv);
    else setV2(nv);
  };

  const handlePointerUp = () => setDragging(null);

  const drawArrow = (from, to, color, sw, opts) => {
    const dashed = opts && opts.dashed;
    const opac = (opts && opts.opacity) || 1;
    const [x1, y1] = toSvg(from[0], from[1]);
    const [x2, y2] = toSvg(to[0], to[1]);
    const dx = x2 - x1, dy = y2 - y1;
    const len = Math.sqrt(dx * dx + dy * dy);
    if (len < 3) return null;
    const nx = dx / len, ny = dy / len;
    const hl = Math.min(10, len * 0.3);
    const hw = 4;
    const bx = x2 - nx * hl, by = y2 - ny * hl;
    return (
      <g opacity={opac}>
        <line x1={x1} y1={y1} x2={bx} y2={by}
          stroke={color} strokeWidth={sw}
          strokeDasharray={dashed ? '5,3' : 'none'} />
        <polygon
          points={x2 + ',' + y2 + ' ' + (bx + ny * hw) + ',' + (by - nx * hw) + ' ' + (bx - ny * hw) + ',' + (by + nx * hw)}
          fill={color} />
      </g>
    );
  };

  const presets = [
    { name: 'Example', a: [1, 0], b: [1, 1] },
    { name: 'Angled', a: [3, 1], b: [1, 3] },
    { name: 'Parallel', a: [2, 1], b: [4, 2] },
    { name: 'Orthogonal', a: [3, 0], b: [0, 2] },
  ];

  const isParallel = u1 && !u2;
  const isOrthog = u1 && u2 && Math.abs(projScalar) < 0.05;
  const basisDim = u1 ? (u2 ? 2 : 1) : 0;

  var insight;
  if (n1 < 1e-10) {
    insight = 'v1 is zero -- no basis can be formed.';
  } else if (isParallel) {
    insight = 'Vectors are parallel (linearly dependent). Only 1 basis vector!';
  } else if (isOrthog) {
    insight = 'Already orthogonal! Projection is ~0, just normalize each.';
  } else {
    insight = 'proj(v2, u1) = ' + projScalar.toFixed(2) + ' * u1. Subtract to get perpendicular w2.';
  }

  var basisShowScale = 1.8;

  var rightAngle = null;
  if (u1 && u2 && Math.abs(projScalar) > 0.05) {
    var s = 0.25;
    var px = proj[0], py = proj[1];
    var d2n = Math.sqrt(w2[0] * w2[0] + w2[1] * w2[1]);
    if (d2n > 0.01) {
      var d2 = [w2[0] / d2n, w2[1] / d2n];
      var pa = toSvg(px + u1[0] * s, py + u1[1] * s);
      var pb = toSvg(px + u1[0] * s + d2[0] * s, py + u1[1] * s + d2[1] * s);
      var pc = toSvg(px + d2[0] * s, py + d2[1] * s);
      rightAngle = (
        <polyline
          points={pa[0] + ',' + pa[1] + ' ' + pb[0] + ',' + pb[1] + ' ' + pc[0] + ',' + pc[1]}
          fill="none" stroke={theme.colors.textSecondary} strokeWidth={1} />
      );
    }
  }

  var projLabel = null;
  if (u1 && !isParallel && Math.abs(projScalar) > 0.05) {
    var mid = toSvg(proj[0] / 2, proj[1] / 2);
    projLabel = (
      <text x={mid[0]} y={mid[1] + 14}
        fill={theme.colors.orange} fontSize={10} fontFamily={theme.font}
        textAnchor="middle">proj</text>
    );
  }

  return (
    <div style={{
      maxWidth: 600, margin: '0 auto', fontFamily: theme.font,
      background: theme.colors.background, color: theme.colors.text,
      maxHeight: 500, overflow: 'hidden', borderRadius: 12,
      border: '1px solid ' + theme.colors.border
    }}>
      <div style={{
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        padding: '8px 14px', borderBottom: '1px solid ' + theme.colors.border,
        background: theme.colors.surfaceAlt
      }}>
        <span style={{ fontSize: 15, fontWeight: 700 }}>Gram-Schmidt Process</span>
        <div style={{ display: 'flex', gap: 5 }}>
          {presets.map(function(p) {
            return (
              <button key={p.name}
                onClick={function() { setV1(p.a); setV2(p.b); }}
                style={{
                  padding: '3px 8px', fontSize: 10, fontFamily: theme.font, fontWeight: 600,
                  background: theme.colors.surface, border: '1px solid ' + theme.colors.border,
                  color: theme.colors.textSecondary, borderRadius: 5, cursor: 'pointer'
                }}>{p.name}</button>
            );
          })}
        </div>
      </div>

      <svg ref={svgRef} viewBox={'0 0 ' + W + ' ' + H}
        style={{ width: '100%', display: 'block', background: theme.colors.surface }}
        onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}>

        {Array.from({ length: 19 }, function(_, i) { return i - 9; }).map(function(n) {
          var a1 = toSvg(n, -9);
          var a2 = toSvg(n, 9);
          var b1 = toSvg(-9, n);
          var b2 = toSvg(9, n);
          var isAxis = n === 0;
          return (
            <g key={n}>
              <line x1={a1[0]} y1={a1[1]} x2={a2[0]} y2={a2[1]}
                stroke={isAxis ? '#555' : theme.colors.border} strokeWidth={isAxis ? 1.2 : 0.3} />
              <line x1={b1[0]} y1={b1[1]} x2={b2[0]} y2={b2[1]}
                stroke={isAxis ? '#555' : theme.colors.border} strokeWidth={isAxis ? 1.2 : 0.3} />
            </g>
          );
        })}

        <circle cx={ox} cy={oy} r={sc} fill="none"
          stroke={theme.colors.textMuted} strokeWidth={1} strokeDasharray="4,4" opacity={0.4} />
        <text x={ox + sc + 4} y={oy - 4} fill={theme.colors.textMuted}
          fontSize={9} fontFamily={theme.font}>r=1</text>

        {u1 && !isParallel && Math.abs(projScalar) > 0.05 && (
          <g>
            {drawArrow([0, 0], proj, theme.colors.orange, 1.5, { dashed: true, opacity: 0.8 })}
            <line x1={toSvg(proj[0], proj[1])[0]} y1={toSvg(proj[0], proj[1])[1]}
              x2={toSvg(v2[0], v2[1])[0]} y2={toSvg(v2[0], v2[1])[1]}
              stroke={theme.colors.yellow} strokeWidth={1.5} strokeDasharray="5,3" opacity={0.7} />
            {rightAngle}
            {projLabel}
            <text x={(toSvg(proj[0], proj[1])[0] + toSvg(v2[0], v2[1])[0]) / 2 + 10}
              y={(toSvg(proj[0], proj[1])[1] + toSvg(v2[0], v2[1])[1]) / 2}
              fill={theme.colors.yellow} fontSize={10} fontFamily={theme.font}
              textAnchor="middle">w2</text>
          </g>
        )}

        {drawArrow([0, 0], v1, theme.colors.blue, 2.5, {})}
        {drawArrow([0, 0], v2, theme.colors.pink, 2.5, {})}

        {u1 && drawArrow([0, 0], [u1[0] * basisShowScale, u1[1] * basisShowScale], theme.colors.green, 3, {})}
        {u2 && drawArrow([0, 0], [u2[0] * basisShowScale, u2[1] * basisShowScale], theme.colors.yellow, 3, {})}

        {u1 && <circle cx={toSvg(u1[0], u1[1])[0]} cy={toSvg(u1[0], u1[1])[1]} r={3.5} fill={theme.colors.green} opacity={0.8} />}
        {u2 && <circle cx={toSvg(u2[0], u2[1])[0]} cy={toSvg(u2[0], u2[1])[1]} r={3.5} fill={theme.colors.yellow} opacity={0.8} />}

        {u1 && (
          <text x={toSvg(u1[0] * basisShowScale, u1[1] * basisShowScale)[0] + 10}
            y={toSvg(u1[0] * basisShowScale, u1[1] * basisShowScale)[1] + 5}
            fill={theme.colors.green} fontSize={12} fontFamily={theme.font} fontWeight="bold">u1</text>
        )}
        {u2 && (
          <text x={toSvg(u2[0] * basisShowScale, u2[1] * basisShowScale)[0] + 10}
            y={toSvg(u2[0] * basisShowScale, u2[1] * basisShowScale)[1] + 5}
            fill={theme.colors.yellow} fontSize={12} fontFamily={theme.font} fontWeight="bold">u2</text>
        )}

        {[{ v: v1, id: 'v1', c: theme.colors.blue }, { v: v2, id: 'v2', c: theme.colors.pink }].map(function(item) {
          var sv = toSvg(item.v[0], item.v[1]);
          return (
            <g key={item.id} style={{ cursor: dragging === item.id ? 'grabbing' : 'grab' }}
              onPointerDown={handlePointerDown(item.id)}>
              <circle cx={sv[0]} cy={sv[1]} r={14} fill={item.c} fillOpacity={0.12}
                stroke={item.c} strokeWidth={2} />
              <circle cx={sv[0]} cy={sv[1]} r={4} fill={item.c} />
              <text x={sv[0] + 18} y={sv[1] - 10}
                fill={item.c} fontSize={11} fontFamily={theme.font} fontWeight="bold">
                {item.id + ' [' + item.v[0] + ', ' + item.v[1] + ']'}
              </text>
            </g>
          );
        })}

        <text x={ox + 6} y={oy + 14} fill={theme.colors.textMuted} fontSize={10} fontFamily={theme.font}>O</text>

        <g transform={'translate(' + (W - 120) + ', 14)'}>
          <rect x={0} y={0} width={110} height={60} rx={6} fill={theme.colors.surfaceAlt} fillOpacity={0.9}
            stroke={theme.colors.border} strokeWidth={0.5} />
          <circle cx={12} cy={16} r={4} fill={theme.colors.blue} />
          <text x={22} y={19} fill={theme.colors.blue} fontSize={10} fontFamily={theme.font}>v1 input</text>
          <circle cx={12} cy={32} r={4} fill={theme.colors.pink} />
          <text x={22} y={35} fill={theme.colors.pink} fontSize={10} fontFamily={theme.font}>v2 input</text>
          <circle cx={12} cy={48} r={4} fill={theme.colors.green} />
          <text x={22} y={51} fill={theme.colors.green} fontSize={10} fontFamily={theme.font}>u1</text>
          <circle cx={52} cy={48} r={4} fill={theme.colors.yellow} />
          <text x={62} y={51} fill={theme.colors.yellow} fontSize={10} fontFamily={theme.font}>u2</text>
        </g>
      </svg>

      <div style={{
        padding: '8px 14px', borderTop: '1px solid ' + theme.colors.border,
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        background: theme.colors.surfaceAlt, fontSize: 11
      }}>
        <div style={{ display: 'flex', gap: 14 }}>
          {u1 && (
            <span>
              <span style={{ color: theme.colors.green, fontWeight: 700 }}>u1</span>
              <span style={{ color: theme.colors.textSecondary }}>{' = [' + u1[0].toFixed(3) + ', ' + u1[1].toFixed(3) + ']'}</span>
            </span>
          )}
          {u2 && (
            <span>
              <span style={{ color: theme.colors.yellow, fontWeight: 700 }}>u2</span>
              <span style={{ color: theme.colors.textSecondary }}>{' = [' + u2[0].toFixed(3) + ', ' + u2[1].toFixed(3) + ']'}</span>
            </span>
          )}
          {!u1 && <span style={{ color: theme.colors.textMuted }}>Set v1 to a non-zero vector</span>}
        </div>
        <span style={{ color: isParallel ? theme.colors.orange : theme.colors.green, fontWeight: 600 }}>
          {'dim = ' + basisDim}
        </span>
      </div>

      <div style={{
        padding: '6px 14px', fontSize: 10, color: theme.colors.textMuted,
        borderTop: '1px solid ' + theme.colors.border, textAlign: 'center'
      }}>
        {insight + '  |  Drag the dots to explore.'}
      </div>
    </div>
  );
}
